import{_ as a,o,c as n,ai as d}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Cron Add Hardening","description":"","frontmatter":{"summary":"Harden cron.add input handling, align schemas, and improve cron UI/agent tooling","owner":"opensoul","status":"complete","last_updated":"2026-01-05","title":"Cron Add Hardening"},"headers":[],"relativePath":"experiments/plans/cron-add-hardening.md","filePath":"experiments/plans/cron-add-hardening.md","lastUpdated":null}'),i={name:"experiments/plans/cron-add-hardening.md"};function r(s,e,t,c,l,h){return o(),n("div",null,[...e[0]||(e[0]=[d('<h1 id="cron-add-hardening-schema-alignment" tabindex="-1"><a class="header-anchor" href="#cron-add-hardening-schema-alignment">#</a> Cron Add Hardening &amp; Schema Alignment</h1><h2 id="context" tabindex="-1"><a class="header-anchor" href="#context">#</a> Context</h2><p>Recent gateway logs show repeated <code>cron.add</code> failures with invalid parameters (missing <code>sessionTarget</code>, <code>wakeMode</code>, <code>payload</code>, and malformed <code>schedule</code>). This indicates that at least one client (likely the agent tool call path) is sending wrapped or partially specified job payloads. Separately, there is drift between cron provider enums in TypeScript, gateway schema, CLI flags, and UI form types, plus a UI mismatch for <code>cron.status</code> (expects <code>jobCount</code> while gateway returns <code>jobs</code>).</p><h2 id="goals" tabindex="-1"><a class="header-anchor" href="#goals">#</a> Goals</h2><ul><li>Stop <code>cron.add</code> INVALID_REQUEST spam by normalizing common wrapper payloads and inferring missing <code>kind</code> fields.</li><li>Align cron provider lists across gateway schema, cron types, CLI docs, and UI forms.</li><li>Make agent cron tool schema explicit so the LLM produces correct job payloads.</li><li>Fix the Control UI cron status job count display.</li><li>Add tests to cover normalization and tool behavior.</li></ul><h2 id="non-goals" tabindex="-1"><a class="header-anchor" href="#non-goals">#</a> Non-goals</h2><ul><li>Change cron scheduling semantics or job execution behavior.</li><li>Add new schedule kinds or cron expression parsing.</li><li>Overhaul the UI/UX for cron beyond the necessary field fixes.</li></ul><h2 id="findings-current-gaps" tabindex="-1"><a class="header-anchor" href="#findings-current-gaps">#</a> Findings (current gaps)</h2><ul><li><code>CronPayloadSchema</code> in gateway excludes <code>signal</code> + <code>imessage</code>, while TS types include them.</li><li>Control UI CronStatus expects <code>jobCount</code>, but gateway returns <code>jobs</code>.</li><li>Agent cron tool schema allows arbitrary <code>job</code> objects, enabling malformed inputs.</li><li>Gateway strictly validates <code>cron.add</code> with no normalization, so wrapped payloads fail.</li></ul><h2 id="what-changed" tabindex="-1"><a class="header-anchor" href="#what-changed">#</a> What changed</h2><ul><li><code>cron.add</code> and <code>cron.update</code> now normalize common wrapper shapes and infer missing <code>kind</code> fields.</li><li>Agent cron tool schema matches the gateway schema, which reduces invalid payloads.</li><li>Provider enums are aligned across gateway, CLI, UI, and macOS picker.</li><li>Control UI uses the gateway’s <code>jobs</code> count field for status.</li></ul><h2 id="current-behavior" tabindex="-1"><a class="header-anchor" href="#current-behavior">#</a> Current behavior</h2><ul><li><strong>Normalization:</strong> wrapped <code>data</code>/<code>job</code> payloads are unwrapped; <code>schedule.kind</code> and <code>payload.kind</code> are inferred when safe.</li><li><strong>Defaults:</strong> safe defaults are applied for <code>wakeMode</code> and <code>sessionTarget</code> when missing.</li><li><strong>Providers:</strong> Discord/Slack/Signal/iMessage are now consistently surfaced across CLI/UI.</li></ul><p>See <a href="/docs/automation/cron-jobs">Cron jobs</a> for the normalized shape and examples.</p><h2 id="verification" tabindex="-1"><a class="header-anchor" href="#verification">#</a> Verification</h2><ul><li>Watch gateway logs for reduced <code>cron.add</code> INVALID_REQUEST errors.</li><li>Confirm Control UI cron status shows job count after refresh.</li></ul><h2 id="optional-follow-ups" tabindex="-1"><a class="header-anchor" href="#optional-follow-ups">#</a> Optional Follow-ups</h2><ul><li>Manual Control UI smoke: add a cron job per provider + verify status job count.</li></ul><h2 id="open-questions" tabindex="-1"><a class="header-anchor" href="#open-questions">#</a> Open Questions</h2><ul><li>Should <code>cron.add</code> accept explicit <code>state</code> from clients (currently disallowed by schema)?</li><li>Should we allow <code>webchat</code> as an explicit delivery provider (currently filtered in delivery resolution)?</li></ul>',20)])])}const g=a(i,[["render",r]]);export{u as __pageData,g as default};
